-- =============================================================================
-- UniWell Campus Healthcare — BULK Seed Data (Past 2 Months)
-- Run this in Supabase Dashboard → SQL Editor
-- =============================================================================
-- Prerequisites: Run seed-users.js first to create staff auth accounts.
-- =============================================================================

DO $$
DECLARE
  v_doctor_id        uuid;
  v_pharmacy_id      uuid;
  v_insurance_id     uuid;
  v_medcenter_id     uuid;

  v_s1 uuid := 'aaaaaaaa-0001-0000-0000-000000000000';
  v_s2 uuid := 'aaaaaaaa-0002-0000-0000-000000000000';
  v_s3 uuid := 'aaaaaaaa-0003-0000-0000-000000000000';
  v_s4 uuid := 'aaaaaaaa-0004-0000-0000-000000000000';
  v_s5 uuid := 'aaaaaaaa-0005-0000-0000-000000000000';
  v_s6 uuid := 'aaaaaaaa-0006-0000-0000-000000000000';
  v_s7 uuid := 'aaaaaaaa-0007-0000-0000-000000000000';
  v_s8 uuid := 'aaaaaaaa-0008-0000-0000-000000000000';
  v_s9 uuid := 'aaaaaaaa-0009-0000-0000-000000000000';
  v_s10 uuid := 'aaaaaaaa-0010-0000-0000-000000000000';
  v_s11 uuid := 'aaaaaaaa-0011-0000-0000-000000000000';
  v_s12 uuid := 'aaaaaaaa-0012-0000-0000-000000000000';
  v_s13 uuid := 'aaaaaaaa-0013-0000-0000-000000000000';
  v_s14 uuid := 'aaaaaaaa-0014-0000-0000-000000000000';
  v_s15 uuid := 'aaaaaaaa-0015-0000-0000-000000000000';
  v_s16 uuid := 'aaaaaaaa-0016-0000-0000-000000000000';
  v_s17 uuid := 'aaaaaaaa-0017-0000-0000-000000000000';
  v_s18 uuid := 'aaaaaaaa-0018-0000-0000-000000000000';
  v_s19 uuid := 'aaaaaaaa-0019-0000-0000-000000000000';
  v_s20 uuid := 'aaaaaaaa-0020-0000-0000-000000000000';
  v_s21 uuid := 'aaaaaaaa-0021-0000-0000-000000000000';
  v_s22 uuid := 'aaaaaaaa-0022-0000-0000-000000000000';
  v_s23 uuid := 'aaaaaaaa-0023-0000-0000-000000000000';
  v_s24 uuid := 'aaaaaaaa-0024-0000-0000-000000000000';
  v_s25 uuid := 'aaaaaaaa-0025-0000-0000-000000000000';
  v_s26 uuid := 'aaaaaaaa-0026-0000-0000-000000000000';
  v_s27 uuid := 'aaaaaaaa-0027-0000-0000-000000000000';
  v_s28 uuid := 'aaaaaaaa-0028-0000-0000-000000000000';
  v_s29 uuid := 'aaaaaaaa-0029-0000-0000-000000000000';
  v_s30 uuid := 'aaaaaaaa-0030-0000-0000-000000000000';
  v_s31 uuid := 'aaaaaaaa-0031-0000-0000-000000000000';
  v_s32 uuid := 'aaaaaaaa-0032-0000-0000-000000000000';
  v_s33 uuid := 'aaaaaaaa-0033-0000-0000-000000000000';
  v_s34 uuid := 'aaaaaaaa-0034-0000-0000-000000000000';
  v_s35 uuid := 'aaaaaaaa-0035-0000-0000-000000000000';
  v_s36 uuid := 'aaaaaaaa-0036-0000-0000-000000000000';
  v_s37 uuid := 'aaaaaaaa-0037-0000-0000-000000000000';
  v_s38 uuid := 'aaaaaaaa-0038-0000-0000-000000000000';
  v_s39 uuid := 'aaaaaaaa-0039-0000-0000-000000000000';
  v_s40 uuid := 'aaaaaaaa-0040-0000-0000-000000000000';
  v_s41 uuid := 'aaaaaaaa-0041-0000-0000-000000000000';
  v_s42 uuid := 'aaaaaaaa-0042-0000-0000-000000000000';
  v_s43 uuid := 'aaaaaaaa-0043-0000-0000-000000000000';
  v_s44 uuid := 'aaaaaaaa-0044-0000-0000-000000000000';
  v_s45 uuid := 'aaaaaaaa-0045-0000-0000-000000000000';
  v_s46 uuid := 'aaaaaaaa-0046-0000-0000-000000000000';
  v_s47 uuid := 'aaaaaaaa-0047-0000-0000-000000000000';
  v_s48 uuid := 'aaaaaaaa-0048-0000-0000-000000000000';
  v_s49 uuid := 'aaaaaaaa-0049-0000-0000-000000000000';
  v_s50 uuid := 'aaaaaaaa-0050-0000-0000-000000000000';

BEGIN

  -- ── Look up existing staff profiles from seed-users.js ─────────────────
  SELECT p.id INTO v_doctor_id     FROM public.profiles p WHERE p.email = 'doctor@sau.edu.in' LIMIT 1;
  SELECT p.id INTO v_pharmacy_id   FROM public.profiles p WHERE p.email = 'pharmacy@sau.edu.in' LIMIT 1;
  SELECT p.id INTO v_insurance_id  FROM public.profiles p WHERE p.email = 'insurance@sau.edu.in' LIMIT 1;
  SELECT p.id INTO v_medcenter_id  FROM public.profiles p WHERE p.email = 'medicalcenter@sau.edu.in' LIMIT 1;
  
  IF v_doctor_id IS NULL OR v_pharmacy_id IS NULL THEN
    RAISE EXCEPTION 'Staff not found! Run seed-users.js first, then re-run this script.';
  END IF;

  -- ── Update existing staff profile details ──────────────────────────────
  UPDATE public.profiles SET phone = '+91 9800000001', college_id = 'STAFF-DOC1' WHERE email = 'doctor@sau.edu.in';
  UPDATE public.profiles SET phone = '+91 9800000002', college_id = 'STAFF-002' WHERE email = 'pharmacy@sau.edu.in';
  UPDATE public.profiles SET phone = '+91 9800000003', college_id = 'STAFF-003' WHERE email = 'insurance@sau.edu.in';
  UPDATE public.profiles SET phone = '+91 9800000004', college_id = 'STAFF-004' WHERE email = 'medicalcenter@sau.edu.in';

  -- ─────────────────────────────────────────────────────────────────────────
  -- STEP 1: Create student & doctor auth.users entries
  -- ─────────────────────────────────────────────────────────────────────────
  ON CONFLICT (id) DO NOTHING;

  -- ─────────────────────────────────────────────────────────────────────────
  -- STEP 2: Insert student & doctor profiles
  -- ─────────────────────────────────────────────────────────────────────────
  ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, roles = EXCLUDED.roles, phone = EXCLUDED.phone, class = EXCLUDED.class, branch = EXCLUDED.branch, batch = EXCLUDED.batch, college_id = EXCLUDED.college_id, blood_group = EXCLUDED.blood_group, medical_conditions = EXCLUDED.medical_conditions;

  -- ─────────────────────────────────────────────────────────────────────────
  -- STEP 3: Pharmacy Inventory
  -- ─────────────────────────────────────────────────────────────────────────
  ON CONFLICT (id) DO NOTHING;

  -- ─────────────────────────────────────────────────────────────────────────
  -- STEP 4: Appointments
  -- ─────────────────────────────────────────────────────────────────────────

  -- ─────────────────────────────────────────────────────────────────────────
  -- STEP 5: Medical Records (Patient is student, Doctor is treating)
  -- ─────────────────────────────────────────────────────────────────────────

  -- ─────────────────────────────────────────────────────────────────────────
  -- STEP 6: Prescriptions
  -- ─────────────────────────────────────────────────────────────────────────

  -- ─────────────────────────────────────────────────────────────────────────
  -- STEP 7: Pharmacy Orders
  -- ─────────────────────────────────────────────────────────────────────────

  -- ─────────────────────────────────────────────────────────────────────────
  -- STEP 8: Insurance Claims
  -- ─────────────────────────────────────────────────────────────────────────

  -- ─────────────────────────────────────────────────────────────────────────
  -- STEP 9: Medical Leave Applications
  -- ─────────────────────────────────────────────────────────────────────────

  -- ─────────────────────────────────────────────────────────────────────────
  -- STEP 10: SOS Requests
  -- ─────────────────────────────────────────────────────────────────────────

  RAISE NOTICE '✅ Bulk Seed complete! Students: 50 | Appts: 200 | Records: 200 | Prescriptions: 150 | Orders: 100 | Claims: 80 | Leave: 60 | SOS: 30';
END $$;
